INSERT INTO `produtos` (`id`, `titulo`, `subtitulo`, `id_categoria`, `id_subcategoria`, `imagem`, `caracteristicas`, `video`, `descricao`, `arquivo_pdf`, `slug`, `modelos`) VALUES
(63, 'Injetora tipo C', '', 100, 6, 'cr-produtos3.png', '<ul><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Forma construtiva Tipo “C”, area de trabalho sem obstruções,\r\nfacilitando acesso para troca/fixação de moldes</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Modelos com 01 ou 02 células de injeção, com controles de\r\nfluxo, pressão e tempo do ciclo injeção individuais</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Quando o ciclo de injeção excede o de extração, no modelo de\r\n02 células pode ser supervisionado por 01 operador, duplicando a eficiência e\r\nreduzindo custos com mão de obra</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Bico injeção cera horizontal</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Controle de temperatura em 04 zonas: tanque, ambiente,\r\nmangueira e bico de injeção</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Sistema de purga automático, substituindo a cera parada no\r\nsistema por cera fresca e homogênea, para uma ótima performance na injeção</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Extração de peças pneumático, com acionamento através de\r\npedal</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Ajustes posição do bico</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Comando PLC processo e segurança integrado, para\r\nmonitoramento e gerenciamento de funções e dispositivo de segurança.</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Interface de\r\ngerenciamento de funções de fácil operação</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Garantia de 12 meses</span></li></ul><p style=\"margin-left: 18pt;\"><b style=\"text-indent: 18pt;\"><span style=\"font-size:9.0pt;line-height:107%\">Opcionais:</span></b></p><ul><li style=\"margin-left: 18pt;\"><span style=\"font-size: 9pt;\">No modelo de 02 células de injeção, pode ser usado\r\nreservatório adicional para cera, com capacidade de 150 L, possibilitando uso\r\nde ceras de tipos e temperaturas diferentes.</span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Bico injeção cera vertical<o:p></o:p></span></li></ul>', '', 'A CECOMATEC oferece diversos modelos de injetora de cera, para indústrias de Microfusão / Fundição de precisão possibilitando a fabricação dos mais variados modelos de peças em cera, para segmentos automotivo, próteses, válvulas entre outros. \r\nFOCO NO ATENDIMENTO DO PROCESSO DO CLIENTE, FABRICANDO PRODUTOS DE ALTA DURABILIDADE E TECNOLOGIA AVANÇADA.\r\nDependendo do modelo de peça a ser injetado, o projeto da máquina pode ser ajustado, indo de encontro as necessidades de cada cliente.\r\nFABRICAÇÃO NACIONAL:\r\nTotalmente adequada as exigências da norma brasileira de segurança (NR12)\r\nSuporte técnico e assistência nacional, proporcionando menores custos e tempo de parada\r\nFinanciamento facilitado via FINAME e Cartão BNDES.', '', 'injetora-tipo-c', '<h6><table class=\"MsoNormalTable\" border=\"0\" cellspacing=\"0\" cellpadding=\"0\" width=\"731\" style=\"width: 548.35pt;\">\r\n <tbody><tr style=\"mso-yfti-irow:0;mso-yfti-firstrow:yes;height:27.3pt\">\r\n  <td width=\"105\" nowrap=\"\" colspan=\"2\" style=\"width:78.6pt;border:solid windowtext 1.0pt;\r\n  mso-border-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;height:27.3pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 16pt; font-family: Arial, sans-serif;\">MODELO<o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"69\" style=\"width:51.9pt;border:solid windowtext 1.0pt;border-left:\r\n  none;mso-border-top-alt:solid windowtext .5pt;mso-border-bottom-alt:solid windowtext .5pt;\r\n  mso-border-right-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;\r\n  height:27.3pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 8pt; font-family: Arial, sans-serif;\">Força fechamento<o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"92\" style=\"width:68.95pt;border:solid windowtext 1.0pt;border-left:\r\n  none;mso-border-top-alt:solid windowtext .5pt;mso-border-bottom-alt:solid windowtext .5pt;\r\n  mso-border-right-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;\r\n  height:27.3pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 8pt; font-family: Arial, sans-serif;\">Reservatório hidráulico <o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"55\" style=\"width:41.3pt;border:solid windowtext 1.0pt;border-left:\r\n  none;mso-border-top-alt:solid windowtext .5pt;mso-border-bottom-alt:solid windowtext .5pt;\r\n  mso-border-right-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;\r\n  height:27.3pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 8pt; font-family: Arial, sans-serif;\">Volume cera injeção <o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"62\" style=\"width:46.5pt;border:solid windowtext 1.0pt;border-left:\r\n  none;mso-border-top-alt:solid windowtext .5pt;mso-border-bottom-alt:solid windowtext .5pt;\r\n  mso-border-right-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;\r\n  height:27.3pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\