INSERT INTO `produtos` (`id`, `titulo`, `subtitulo`, `id_categoria`, `id_subcategoria`, `imagem`, `caracteristicas`, `video`, `descricao`, `arquivo_pdf`, `slug`, `modelos`) VALUES
(65, 'Lixadeira de Cinta - Ergonométrica', '', 101, 8, 'cr-produtos5.png', '<ul><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Ergométrica: Regulagem de altura, ajustando área de lixamento\r\nà posição mais adequada de trabalho<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Área de lixamento: polia contato<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Fabricada sob medida para utilização de várias larguras de\r\nlixa <o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Bocal de saída para captação de pó<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Regulagem de esticamento da lixa<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Carenagem para proteção operador<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Capacidade de trabalho em grandes cargas horárias<o:p></o:p></span></li><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Garantia de 12 meses<o:p></o:p></span></li></ul><p class=\"MsoNormal\" style=\"text-indent:18.0pt\"><b><span style=\"font-size:9.0pt;line-height:107%\">Opcionais:<o:p></o:p></span></b></p><ul><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Projetos com automação e gabaritos, para atendimento das mais\r\nvariadas aplicações<o:p></o:p></span></li></ul><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul><li style=\"margin-left: 18pt;\"><span style=\"font-size:9.0pt;\r\nline-height:107%\">Exaustor para captação de pó<o:p></o:p></span></li></ul>', '', 'A CECOMATEC oferece diversos modelos de lixadeira de cinta, para indústrias de fundição, móveis, metalúrgica, serralheria, rebarbação, desbaste e polimento. A lixadeira de cinta industrial ergométrica, tem como característica a possibilidade de regulagem posição de trabalho.\r\n\r\nFOCO NO ATENDIMENTO DO PROCESSO DO CLIENTE, FABRICANDO PRODUTOS DE ALTA DURABILIDADE E TECNOLOGIA AVANÇADA.\r\nDependendo da aplicação, o projeto da máquina pode ser ajustado, indo de encontro as necessidades de cada cliente.\r\n\r\nFABRICAÇÃO NACIONAL:\r\nTotalmente adequada as exigências da norma brasileira de segurança (NR12)\r\nSuporte técnico e assistência nacional, proporcionando menores custos e tempo de parada\r\nFinanciamento facilitado via FINAME e Cartão BNDES.\r\n', '', 'lixadeira-de-cinta-ergonometrica', '<table class=\"MsoNormalTable\" border=\"0\" cellspacing=\"0\" cellpadding=\"0\" width=\"463\" style=\"margin-left: -0.25pt;\">\r\n <tbody><tr style=\"mso-yfti-irow:0;mso-yfti-firstrow:yes;height:23.2pt\">\r\n  <td width=\"128\" nowrap=\"\" colspan=\"2\" style=\"width:96.25pt;border:solid windowtext 1.0pt;\r\n  mso-border-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;height:23.2pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 15pt; font-family: &quot;Arial Narrow&quot;, sans-serif;\">MODELO<o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"79\" style=\"width:59.45pt;border:solid windowtext 1.0pt;border-left:\r\n  none;mso-border-top-alt:solid windowtext .5pt;mso-border-bottom-alt:solid windowtext .5pt;\r\n  mso-border-right-alt:solid windowtext .5pt;padding:0cm 3.5pt 0cm 3.5pt;\r\n  height:23.2pt\">\r\n  <p class=\"MsoNormal\" align=\"center\" style=\"margin-bottom:0cm;margin-bottom:.0001pt;\r\n  text-align:center;line-height:normal\"><b><span style=\"font-size: 8pt; font-family: &quot;Arial Narrow&quot;, sans-serif;\">Lixa<o:p></o:p></span></b></p>\r\n  </td>\r\n  <td width=\"57\" valign=\"top\" style=\"width:42.5pt;border:solid wind